const body = $json.body ?? {};

const audio_base64 = body.audio_base64 ?? '';
const mimeType = body.mimeType ?? 'audio/webm';
const fileName = body.fileName ?? 'voice.webm';

const sessionId = body.sessionId ?? null;
const context = body.context ?? {};

const incomingState = body.state ?? {};
const state = {
  phase: 'idle',
  booking_intent: false,
  pending_slot: null,
  lang: 'en',
  ...incomingState,
};

const binary = audio_base64
  ? {
      audio: {
        data: audio_base64,
        mimeType,
        fileName,
      },
    }
  : {};

return [{ json: { sessionId, context, state, mimeType, fileName }, binary }];

const base = $node["Normalize Voice Input"].json ?? {};
const state = base.state ?? {};

const resp = $json ?? {};

let transcript = '';
let stt_error = '';

if (resp?.error?.message) {
  stt_error = String(resp.error.message);
}

if (!stt_error) {
  if (typeof resp?.text === 'string') transcript = resp.text;
  else if (typeof resp?.body?.text === 'string') transcript = resp.body.text;
  else if (typeof resp?.data?.text === 'string') transcript = resp.data.text;
}

transcript = (transcript ?? '').toString();
if (!transcript.trim() && !stt_error) stt_error = 'No transcript returned';

return [{ json: { ...base, state, transcript, message: transcript, stt_error } }];

const state = $json.state ?? {};
const hint = ($json.stt_error ?? '').toString();
const replyBase = 'I could not understand the voice message. Please try again or type it.';
const reply = hint ? `${replyBase} (${hint})` : replyBase;
return [{ json: { reply, booking_intent: false, state, transcript: '' } }];

const body = $json.body ?? {};

const message = body.message ?? body.user_message ?? '';
const sessionId = body.sessionId ?? null;
const context = body.context ?? {};

const incomingState = body.state ?? {};
const state = {
  phase: 'idle',
  booking_intent: false,
  pending_slot: null,
  lang: 'en',
  ...incomingState,
};

return [{ json: { message, sessionId, context, state } }];

const agent_context = `Du bist Stefans KI‑Buchungsassistent.

Dein Hauptzweck: Nutzer können hier schnell ein 30‑min Meeting mit Stefan organisieren.
Wenn der Nutzer einfach nur Smalltalk macht, antworte kurz freundlich und erkläre direkt, dass du Termine mit Stefan buchen kannst, und frage nach einem Wunschtermin (Wochentag + Uhrzeit) oder ob du freie Slots vorschlagen sollst.
Erfinde keine Fakten über Stefan (z.B. Alter, Adresse, private Details). Wenn etwas nicht im Kontext steht, sag ehrlich, dass du es nicht weißt und biete an, stattdessen einen Termin zu buchen.`.trim();

return [{ json: { ...$json, agent_context } }];

function parseBool(v, defaultValue = true) {
  if (v === undefined || v === null) return defaultValue;
  const s = String(v).trim().toLowerCase();
  if (['1', 'true', 'yes', 'y', 'on'].includes(s)) return true;
  if (['0', 'false', 'no', 'n', 'off'].includes(s)) return false;
  return defaultValue;
}

function parseCsv(v) {
  return String(v ?? '')
    .split(',')
    .map((s) => s.trim().toLowerCase())
    .filter(Boolean);
}

const allowed = new Set(['email', 'name', 'phone', 'note']);
const requiredInputs = parseCsv($env.REQUIRE_INPUT).filter((x) => allowed.has(x));
const optionalInputs = parseCsv($env.OPTIONAL_INPUT).filter((x) => allowed.has(x));

const policy = {
  tz: ($env.AGENT_TZ ?? $env.TZ ?? 'Europe/Berlin').toString(),
  workdays: ($env.AGENT_WORKDAYS ?? '1,2,3,4,5').toString(),
  workStart: ($env.AGENT_WORK_START ?? '09:00').toString(),
  workEnd: ($env.AGENT_WORK_END ?? '17:00').toString(),
  horizonDays: Number($env.AGENT_HORIZON_DAYS ?? 30) || 30,
  minLeadHours: Number($env.AGENT_MIN_LEAD_HOURS ?? 24) || 24,
  durationMinutes: 30,
  createGoogleMeet: parseBool($env.CREATE_GOOGLE_MEET, true),
  requiredInputs,
  optionalInputs,
};

const agent_context = ($json.agent_context ?? '').toString().trim();

return [{ json: { ...$json, policy, agent_context, now_iso: new Date().toISOString() } }];

