={{JSON.stringify((() => {
  const baseSystemLines = [
    'You are a booking assistant. Return ONLY strict JSON.',
    '',
    'Output schema:',
    '{',
    '  "language": string,',
    '  "reply": string,',
    '  "booking_intent": boolean,',
    '  "confirm_booking": boolean,',
    '  "datetime_text": string|null,',
    '  "state_update": object',
    '}',
    '',
    'Rules:',
    '- language MUST be the user\'s language as a 2-letter ISO 639-1 code when possible (e.g. "fr", "de", "en").',
    '- reply MUST be in language.',
    '- language MUST match reply (e.g. German reply -> language="de").',
    '- If language is "de": use informal "du" (not "Sie").',
    '- If booking_intent is false: confirm_booking MUST be false and datetime_text MUST be null.',
    '- If state.phase=="awaiting_confirm" and user clearly confirms: confirm_booking MUST be true.',
    '- If user provides a date/time: set booking_intent=true AND set datetime_text to the date/time phrase.',
    '  - Treat bare hours like "at 10" / "um 10" / "Dienstag 12" as a time (10:00 / 12:00).',
    '  - Examples that MUST set datetime_text: "next Monday at 10", "Dienstag 12:30", "Tuesday 14:00".',
    '- If user wants booking but no date/time: set booking_intent=true and datetime_text=null.',
    '- If user asks about weekends / Saturday / Sunday (without a specific time): reply that bookings are only on workdays and during policy hours, and ask for an alternative.',
    '- If the user asks you to suggest a meeting time / propose available slots: set booking_intent=true, datetime_text=null, confirm_booking=false, and set state_update.action=\"suggest_slots\".',
    '- If the user asks to suggest slots, do NOT say please wait/one moment. Just proceed.',
    '- When you ask the user for a date/time, include the allowed window from policy (workdays + workStart-workEnd).',
    '- Reply should be short (1-2 sentences).',
    '- No markdown, no backticks, no extra keys.',
  ];

  const agentContext = ($json.agent_context ?? '').toString().trim();
  const systemLines = agentContext
    ? baseSystemLines.concat(['', 'Agent context (system):', agentContext])
    : baseSystemLines;

  const userMessage = ($json.message ?? '').toString();

  return {
    model: 'gpt-4o-mini',
    temperature: 0.2,
    messages: [
      {
        role: 'system',
        content: systemLines.join('\n'),
      },
      {
        role: 'user',
        content: [
          'User message:',
          userMessage,
          '',
          'Context JSON:',
          JSON.stringify({
            now_iso: $json.now_iso,
            state: $json.state,
            policy: $json.policy,
          }),
        ].join('\n'),
      },
    ],
    response_format: { type: 'json_object' },
  };
})())}}

