const input = $node['Policy + Now'].json;
const state = input.state ?? {};

function normLang(value) {
  const s = (value ?? '').toString().trim().toLowerCase();
  const m = s.match(/^[a-z]{2}/);
  return m ? m[0] : 'en';
}

function parseInputs(value) {
  const allowed = new Set(['email', 'name', 'phone', 'note']);
  if (Array.isArray(value)) {
    return value
      .map((x) => String(x).trim().toLowerCase())
      .filter((x) => allowed.has(x));
  }
  if (typeof value === 'string') {
    return value
      .split(',')
      .map((x) => x.trim().toLowerCase())
      .filter((x) => allowed.has(x));
  }
  return [];
}

function getContact(s) {
  const c = s?.contact;
  if (c && typeof c === 'object') return { ...c };
  return {};
}

function extractEmail(text) {
  const m = String(text ?? '').match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return m ? m[0] : null;
}

function extractPhone(text) {
  const raw = String(text ?? '');
  const m = raw.match(/(\+?\d[\d\s\-().]{6,}\d)/);
  if (!m) return null;

  const candidate = m[1].trim();
  const digits = candidate.replace(/\D/g, '');
  if (digits.length < 7) return null;

  return candidate;
}

function looksLikeSkip(text) {
  const s = String(text ?? '').trim().toLowerCase();
  if (!s) return false;
  return ['skip', 'no', 'nope', 'nah', 'nein', 'n', 'later', 'sp\u00e4ter', 'nicht', 'keine', 'kein'].includes(s);
}

function looksLikeYes(text) {
  const s = String(text ?? '').trim().toLowerCase();
  if (!s) return false;
  return ['yes', 'y', 'ja', 'j', 'ok', 'okay', 'sure', 'klar', 'bitte', 'oui', 'si'].includes(s);
}

function looksLikeNo(text) {
  const s = String(text ?? '').trim().toLowerCase();
  if (!s) return false;
  return ['no', 'n', 'nein', 'nope', 'nah', 'non'].includes(s);
}

function missingFields(fields, contact) {
  return fields.filter((f) => {
    const v = contact?.[f];
    return typeof v !== 'string' || !v.trim();
  });
}

function getAttempts(s) {
  const a = s?.input_attempts;
  if (a && typeof a === 'object') return { ...a };
  return {};
}

function bumpAttempt(attempts, field) {
  const n = Number(attempts[field] ?? 0) || 0;
  return { ...attempts, [field]: n + 1 };
}

function askRequiredPrompt(field, attempt) {
  if (field === 'email') {
    return attempt > 0
      ? 'That does not look like an email address. Please send a valid email like name@company.com.'
      : "Before I book this, what's your email address?";
  }
  if (field === 'name') {
    return attempt > 0
      ? 'Please send the name I should use for the booking (e.g. your full name or company name).'
      : 'Before I book this, what name should I use for the booking?';
  }
  if (field === 'phone') {
    return attempt > 0
      ? 'That does not look like a valid phone number. Please send a number like +49 170 1234567.'
      : "Before I book this, what's the best phone number to reach you?";
  }
  if (field === 'note') {
    return attempt > 0
      ? 'Please send a short note I should attach to the calendar invite.'
      : 'Before I book this, do you want me to attach a note to the calendar invite? If yes, tell me the note text.';
  }
  return 'Before I book this, please share the required details.';
}

function offerOptionalPrompt(field) {
  if (field === 'note') return 'Optional: would you like to add a note to the calendar invite?';
  if (field === 'email') return 'Optional: would you like to add your email address to the invite?';
  if (field === 'phone') return 'Optional: would you like to add a phone number to the invite?';
  if (field === 'name') return 'Optional: would you like to add a name to the invite?';
  return 'Optional: would you like to add more details to the invite?';
}

function askOptionalValuePrompt(field, attempt) {
  if (field === 'note') {
    return attempt > 0
      ? 'Please send the note text, or say "skip".'
      : 'What note should I add? (Or say "skip")';
  }
  if (field === 'email') {
    return attempt > 0
      ? 'Please send a valid email address (e.g. name@company.com), or say "skip".'
      : 'What email address should I add? (Or say "skip")';
  }
  if (field === 'phone') {
    return attempt > 0
      ? 'Please send a valid phone number (e.g. +49 170 1234567), or say "skip".'
      : 'What phone number should I add? (Or say "skip")';
  }
  if (field === 'name') {
    return attempt > 0
      ? 'Please send the name, or say "skip".'
      : 'What name should I add? (Or say "skip")';
  }
  return attempt > 0 ? 'Please send the value, or say "skip".' : 'What should I add? (Or say "skip")';
}

function finalize(reply, booking_intent, extraState = {}) {
  const mergedState = { ...state, ...extraState, booking_intent };
  if (!mergedState.lang) mergedState.lang = normLang(state.lang ?? 'en');

  return [
    {
      json: {
        reply,
        booking_intent,
        state: mergedState,
        route: 'final',
        datetime_text: null,
        confirm_booking: false,
        policy: input.policy,
        now_iso: input.now_iso,
        sessionId: input.sessionId ?? null,
        message: input.message ?? '',
      },
    },
  ];
}

function routeConfirm(reply, mergedState) {
  return [
    {
      json: {
        ...input,
        reply,
        booking_intent: true,
        confirm_booking: true,
        datetime_text: null,
        state: mergedState,
        route: 'confirm',
      },
    },
  ];
}

function routeFinalAsk(reply, mergedState) {
  return [
    {
      json: {
        ...input,
        reply,
        booking_intent: true,
        confirm_booking: false,
        datetime_text: null,
        state: mergedState,
        route: 'final',
      },
    },
  ];
}

function routeSuggest(mergedState) {
  return [
    {
      json: {
        ...input,
        reply: 'Suggesting available times.',
        booking_intent: true,
        confirm_booking: false,
        datetime_text: null,
        state: mergedState,
        route: 'suggest',
      },
    },
  ];
}

function parseDeciderResponse() {
  if (typeof $json === 'string' && $json.trim()) {
    const snippet = $json.trim().slice(0, 500);
    return { error: 'LLM error: ' + snippet };
  }

  if ($json?.error?.message) {
    return { error: 'LLM error: ' + String($json.error.message) };
  }

  if (typeof $json?.message === 'string' && $json.message.trim()) {
    return { error: 'LLM error: ' + $json.message.trim() };
  }

  if (!$json || typeof $json !== 'object' || !Array.isArray($json.choices)) {
    return { error: 'LLM is currently unavailable.' };
  }

  const content = $json.choices?.[0]?.message?.content;
  try {
    return { parsed: JSON.parse((content ?? '').toString()) };
  } catch {
    return { error: (content ?? 'LLM returned non-JSON.').toString() };
  }
}

function parseSuggestionSelection(text) {
  const s = String(text ?? '').trim().toLowerCase();
  if (!s) return null;

  const m1 = s.match(/^(?:option\s*)?(\d+)$/i);
  if (m1) return Number(m1[1]);

  const m2 = s.match(/^(\d+)\s*[).:]/);
  if (m2) return Number(m2[1]);

  return null;
}

const dec = parseDeciderResponse();
if (dec.error) return finalize(dec.error, false);

const parsed = dec.parsed ?? {};

const booking_intent = parsed?.booking_intent === true;
const confirm_booking = parsed?.confirm_booking === true;
const datetime_text = typeof parsed?.datetime_text === 'string' ? parsed.datetime_text : null;
const reply = typeof parsed?.reply === 'string' ? parsed.reply : 'OK';
const state_update = parsed?.state_update && typeof parsed.state_update === 'object' ? parsed.state_update : {};
const language = typeof parsed?.language === 'string' ? parsed.language : null;

const lang = normLang(state_update.lang ?? language ?? state.lang ?? 'en');
let newState = { ...state, ...state_update, booking_intent, lang };

const message = (input.message ?? '').toString();
const requiredInputs = parseInputs(input.policy?.requiredInputs);
const optionalInputs = parseInputs(input.policy?.optionalInputs);

let contact = getContact(newState);

const foundEmail = extractEmail(message);
if (foundEmail) contact.email = foundEmail;

const foundPhone = extractPhone(message);
if (foundPhone) contact.phone = foundPhone;

const attempts = getAttempts(newState);

function setFieldValue(field, value) {
  const v = (value ?? '').toString().trim();
  if (!v) return false;

  if (field === 'email') {
    const e = extractEmail(v);
    if (!e) return false;
    contact.email = e;
    return true;
  }

  if (field === 'phone') {
    const p = extractPhone(v);
    if (!p) return false;
    contact.phone = p;
    return true;
  }

  if (field === 'name') {
    const candidate = v;
    if (!candidate || candidate.length > 80) return false;
    if (extractEmail(candidate) || extractPhone(candidate)) return false;
    contact.name = candidate;
    return true;
  }

  if (field === 'note') {
    const candidate = v;
    if (!candidate || candidate.length > 1000) return false;
    contact.note = candidate;
    return true;
  }

  return false;
}

function getOptionalDeclined(s) {
  const v = s?.optional_declined;
  if (Array.isArray(v)) return v.map((x) => String(x).trim().toLowerCase()).filter(Boolean);
  return [];
}

function nextOptionalField() {
  const declined = new Set(getOptionalDeclined(newState));
  const required = new Set(requiredInputs);
  const list = optionalInputs.filter((f) => !required.has(f));

  for (const f of list) {
    if (declined.has(f)) continue;
    const v = contact?.[f];
    if (typeof v === 'string' && v.trim()) continue;
    return f;
  }

  return null;
}

function declineOptional(field) {
  const declined = new Set(getOptionalDeclined(newState));
  declined.add(field);
  newState.optional_declined = Array.from(declined);
}

function proceedAfterInputs() {
  const proceedState = { ...newState, contact, input_attempts: attempts, phase: 'awaiting_confirm' };
  return routeConfirm('Booking now.', proceedState);
}

// If user is choosing one of the suggested slots (1/2/3), map it deterministically.
if (newState.phase === 'choosing_suggestion' && Array.isArray(newState.suggested_slots) && newState.suggested_slots.length > 0) {
  const sel = parseSuggestionSelection(message);
  if (sel !== null && Number.isFinite(sel)) {
    const idx = sel - 1;
    const slot = newState.suggested_slots[idx];
    if (slot && slot.start && slot.end) {
      const padMs = 1;
      const startDate = new Date(slot.start);
      const endDate = new Date(slot.end);
      const pending_slot = {
        start: slot.start,
        end: slot.end,
        queryStart: slot.queryStart ?? new Date(startDate.getTime() + padMs).toISOString(),
        queryEnd: slot.queryEnd ?? new Date(endDate.getTime() - padMs).toISOString(),
        label: slot.label ?? slot.start,
        durationMin: input.policy?.durationMinutes ?? 30,
      };

      const chosenState = {
        ...newState,
        phase: 'awaiting_confirm',
        booking_intent: true,
        pending_slot,
        suggested_slots: null,
      };
      if (chosenState.action) delete chosenState.action;

      return finalize(`I can do ${pending_slot.label}. Should I book the 30min appointment?`, true, chosenState);
    }
  }

  // If they didn't pick a number, continue normal LLM handling.
}

// If we are collecting a specific field (required or optional), handle it deterministically.
if (newState?.collect_field && (newState.phase === 'collect_required' || newState.phase === 'collect_optional_value')) {
  const field = String(newState.collect_field).trim().toLowerCase();

  const isOptional = newState.phase === 'collect_optional_value';
  if (isOptional && looksLikeSkip(message)) {
    declineOptional(field);
    newState.collect_field = null;
    newState.phase = 'collect_optional_offer';
  } else {
    const ok = setFieldValue(field, message);
    if (!ok) {
      const nextAttempts = bumpAttempt(attempts, field);
      newState = { ...newState, contact, input_attempts: nextAttempts };
      const attempt = Number(nextAttempts[field] ?? 1);
      const prompt = isOptional ? askOptionalValuePrompt(field, attempt) : askRequiredPrompt(field, attempt);
      return routeFinalAsk(prompt, newState);
    }

    newState.collect_field = null;
  }

  const stillMissingReq = missingFields(requiredInputs, contact);
  if (stillMissingReq.length > 0) {
    const f = stillMissingReq[0];
    const nextAttempts = bumpAttempt(attempts, f);
    const prompt = askRequiredPrompt(f, Number(nextAttempts[f] ?? 1) - 1);
    newState = { ...newState, contact, phase: 'collect_required', confirmed_booking: true, collect_field: f, input_attempts: nextAttempts };
    return routeFinalAsk(prompt, newState);
  }

  if (newState.confirmed_booking === true && newState?.pending_slot?.start && newState?.pending_slot?.end) {
    const nextOpt = nextOptionalField();
    if (nextOpt) {
      newState = { ...newState, contact, phase: 'collect_optional_offer', optional_offer_field: nextOpt, confirmed_booking: true, input_attempts: attempts };
      return routeFinalAsk(offerOptionalPrompt(nextOpt), newState);
    }
    return proceedAfterInputs();
  }
}

// If we are offering an optional field, interpret yes/no/value.
if (newState.phase === 'collect_optional_offer' && newState.optional_offer_field) {
  const field = String(newState.optional_offer_field).trim().toLowerCase();

  const okDirect = setFieldValue(field, message);
  if (okDirect) {
    newState.optional_offer_field = null;
    const nextOpt = nextOptionalField();
    if (nextOpt) {
      newState = { ...newState, contact, phase: 'collect_optional_offer', optional_offer_field: nextOpt, confirmed_booking: true, input_attempts: attempts };
      return routeFinalAsk(offerOptionalPrompt(nextOpt), newState);
    }
    return proceedAfterInputs();
  }

  if (looksLikeNo(message) || looksLikeSkip(message)) {
    declineOptional(field);
    newState.optional_offer_field = null;

    const nextOpt = nextOptionalField();
    if (nextOpt) {
      newState = { ...newState, contact, phase: 'collect_optional_offer', optional_offer_field: nextOpt, confirmed_booking: true, input_attempts: attempts };
      return routeFinalAsk(offerOptionalPrompt(nextOpt), newState);
    }

    return proceedAfterInputs();
  }

  if (looksLikeYes(message)) {
    const nextAttempts = bumpAttempt(attempts, field);
    newState = { ...newState, contact, phase: 'collect_optional_value', optional_offer_field: null, collect_field: field, confirmed_booking: true, input_attempts: nextAttempts };
    return routeFinalAsk(askOptionalValuePrompt(field, 0), newState);
  }

  newState = { ...newState, contact, input_attempts: attempts };
  return routeFinalAsk(offerOptionalPrompt(field), newState);
}

newState = { ...newState, contact, input_attempts: attempts };

// Start/continue collecting required fields after the user confirmed booking.
if (
  (newState.phase === 'collect_required' || newState.confirmed_booking === true) &&
  newState?.pending_slot?.start &&
  newState?.pending_slot?.end
) {
  const missing = missingFields(requiredInputs, contact);
  if (missing.length > 0) {
    const f = missing[0];
    const nextAttempts = bumpAttempt(attempts, f);
    const prompt = askRequiredPrompt(f, Number(nextAttempts[f] ?? 1) - 1);
    const gatedState = { ...newState, phase: 'collect_required', confirmed_booking: true, collect_field: f, input_attempts: nextAttempts };
    return routeFinalAsk(prompt, gatedState);
  }

  if (newState.confirmed_booking === true) {
    const nextOpt = nextOptionalField();
    if (nextOpt) {
      const optState = { ...newState, contact, phase: 'collect_optional_offer', optional_offer_field: nextOpt, confirmed_booking: true, input_attempts: attempts };
      return routeFinalAsk(offerOptionalPrompt(nextOpt), optState);
    }

    return proceedAfterInputs();
  }
}

// If user requests suggestions, route to suggest pipeline.
const suggestionPatterns = /(\b(suggest|propose|available\s+times?|time\s+slots?|free\s+slots?)\b|\b(vorschl|schlag|freie\s+termine|termine\s+vorschlagen|slots?)\b)/i;
const wantsSuggest = newState?.action === 'suggest_slots' || suggestionPatterns.test(message);
const canSuggestNow = !datetime_text && !confirm_booking && !['collect_required', 'collect_optional_offer', 'collect_optional_value', 'awaiting_confirm'].includes(newState.phase);
if (canSuggestNow && wantsSuggest) {
  const st = { ...newState, booking_intent: true };
  if (st.action === 'suggest_slots') delete st.action;
  st.phase = 'suggesting';
  return routeSuggest(st);
}

// Gate booking confirmation on required/optional fields.
if (booking_intent && confirm_booking && newState.phase === 'awaiting_confirm' && newState?.pending_slot?.start && newState?.pending_slot?.end) {
  const missing = missingFields(requiredInputs, contact);
  if (missing.length > 0) {
    const f = missing[0];
    const nextAttempts = bumpAttempt(attempts, f);
    const gatedState = { ...newState, phase: 'collect_required', confirmed_booking: true, collect_field: f, input_attempts: nextAttempts };
    const prompt = askRequiredPrompt(f, 0);
    return routeFinalAsk(prompt, gatedState);
  }

  const nextOpt = nextOptionalField();
  if (nextOpt) {
    const optState = { ...newState, phase: 'collect_optional_offer', confirmed_booking: true, optional_offer_field: nextOpt, input_attempts: attempts };
    return routeFinalAsk(offerOptionalPrompt(nextOpt), optState);
  }

  return [
    {
      json: {
        ...input,
        reply,
        booking_intent,
        confirm_booking: true,
        datetime_text: null,
        state: newState,
        route: 'confirm',
      },
