function parseHHMM(value, fallback) {
  const m = value?.toString().trim().match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return fallback;
  const hh = Math.min(23, Math.max(0, Number(m[1])));
  const mm = Math.min(59, Math.max(0, Number(m[2])));
  return { hh, mm };
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

function fmtLabel(date) {
  // Use local time of the container (should match policy TZ in this setup)
  return `${date.getFullYear()}-${pad2(date.getMonth() + 1)}-${pad2(date.getDate())} ${pad2(date.getHours())}:${pad2(date.getMinutes())}`;
}

const workdays = (policy.workdays ?? '1,2,3,4,5')
  .toString()
  .split(',')
  .map((s) => Number(s.trim()))
  .filter((n) => Number.isFinite(n));

const ws = parseHHMM(policy.workStart ?? '09:00', { hh: 9, mm: 0 });
const we = parseHHMM(policy.workEnd ?? '17:00', { hh: 17, mm: 0 });
const horizonDays = Math.max(1, Number(policy.horizonDays ?? 30) || 30);
const minLeadHours = Math.max(0, Number(policy.minLeadHours ?? 24) || 24);
const durationMin = Math.max(5, Number(policy.durationMinutes ?? 30) || 30);

const maxCandidates = 10;
const stepMin = 60;

function isWorkday(d) {
  if (!workdays.length) return true;
  return workdays.includes(d.getDay());
}

function setToWorkStart(d) {
  d.setHours(ws.hh, ws.mm, 0, 0);
}

function advanceToNextWorkdayStart(d) {
  d.setDate(d.getDate() + 1);
  setToWorkStart(d);
  while (!isWorkday(d)) {
    d.setDate(d.getDate() + 1);
    setToWorkStart(d);
  }
}

function roundUpTo30Min(d) {
  const ms = d.getTime();
  const step = 30 * 60 * 1000;
  return new Date(Math.ceil(ms / step) * step);
}

const leadMs = minLeadHours > 0 ? minLeadHours * 60 * 60_000 : 0;
let cursor = roundUpTo30Min(new Date(Date.now() + Math.max(60 * 1000, leadMs)));

// Move cursor into working window
const wsMin = ws.hh * 60 + ws.mm;
const weMin = we.hh * 60 + we.mm;

if (!isWorkday(cursor)) {
  setToWorkStart(cursor);
  while (!isWorkday(cursor)) cursor.setDate(cursor.getDate() + 1);
}

let cursorMin = cursor.getHours() * 60 + cursor.getMinutes();
if (cursorMin < wsMin) setToWorkStart(cursor);

cursorMin = cursor.getHours() * 60 + cursor.getMinutes();
if (cursorMin + durationMin > weMin) advanceToNextWorkdayStart(cursor);

const latest = new Date(Date.now() + horizonDays * 24 * 60 * 60_000);

const candidates = [];
while (candidates.length < maxCandidates && cursor.getTime() <= latest.getTime()) {
  if (!isWorkday(cursor)) {
    advanceToNextWorkdayStart(cursor);
    continue;
  }

  const start = new Date(cursor);
  const end = new Date(start.getTime() + durationMin * 60_000);

  const startM = start.getHours() * 60 + start.getMinutes();
  const endM = end.getHours() * 60 + end.getMinutes();

  if (startM < wsMin) {
    setToWorkStart(cursor);
    continue;
  }

  if (endM > weMin) {
    advanceToNextWorkdayStart(cursor);
    continue;
  }

  const padMs = 1;
  const slot = {
    start: start.toISOString(),
    end: end.toISOString(),
    queryStart: new Date(start.getTime() + padMs).toISOString(),
    queryEnd: new Date(end.getTime() - padMs).toISOString(),
    label: fmtLabel(start),
