  };

  candidates.push(slot);

  cursor = new Date(cursor.getTime() + stepMin * 60_000);

  cursorMin = cursor.getHours() * 60 + cursor.getMinutes();
  if (cursorMin + durationMin > weMin) {
    advanceToNextWorkdayStart(cursor);
  }
}

